import{j as a,b as i,c as s,aa as e}from"./chunks/framework.Bxf40uRC.js";const b=JSON.parse('{"title":"Redis持久化","description":"","frontmatter":{},"headers":[],"relativePath":"Redis/Redis持久化.md","filePath":"Redis/Redis持久化.md","lastUpdated":null}'),l={name:"Redis/Redis持久化.md"},t=e(`<h1 id="redis持久化" tabindex="-1">Redis持久化 <a class="header-anchor" href="#redis持久化" aria-label="Permalink to &quot;Redis持久化&quot;">​</a></h1><h2 id="rdb" tabindex="-1">RDB <a class="header-anchor" href="#rdb" aria-label="Permalink to &quot;RDB&quot;">​</a></h2><h3 id="方式" tabindex="-1">方式 <a class="header-anchor" href="#方式" aria-label="Permalink to &quot;方式&quot;">​</a></h3><h4 id="_1、save" tabindex="-1">1、save <a class="header-anchor" href="#_1、save" aria-label="Permalink to &quot;1、save&quot;">​</a></h4><p>执行了save命令，就会在主线程生成RDB文件，由于和执行操作命令在同一个线程，所以如果写入RDB文件的时间太长，就会阻塞主线程；</p><h4 id="_2、bgsave" tabindex="-1">2、bgsave <a class="header-anchor" href="#_2、bgsave" aria-label="Permalink to &quot;2、bgsave&quot;">​</a></h4><p>创建一个子进程来生成RDB文件，这样可以避免主线程的阻塞；</p><blockquote><p>执行快照时，数据能被修改吗？</p></blockquote><p>执行bgsave时候，redis仍然可以继续处理操作命令，也就是数据能够被修改的；</p><h3 id="写时复制技术-cow" tabindex="-1">写时复制技术(COW) <a class="header-anchor" href="#写时复制技术-cow" aria-label="Permalink to &quot;写时复制技术(COW)&quot;">​</a></h3><ol><li>执行bgsave时，通过fork()创建子线程，此时创建的子线程和父线程共享同一片内存区域，因为创建子线程的时候，会复制父进程的页表，但是页表指向的物理内存还是一个； <ul><li>如果该块内存区域没有发生变化，直接进行拷贝即可；</li><li>如果父进程要修改共享数据的某一块数据，就会发生写时复制，于是这块的数据的物理内存就会被复制一份(只有被修改的那块，其余的不变)，然后<strong>主进程在数据副本</strong>进行修改操作，子进程将原来的数据写入到RDB文件中；</li></ul></li></ol><h3 id="优点" tabindex="-1">优点 <a class="header-anchor" href="#优点" aria-label="Permalink to &quot;优点&quot;">​</a></h3><ol><li>保存的是全量的数据，加载速度较AOF快；</li></ol><h3 id="缺点" tabindex="-1">缺点 <a class="header-anchor" href="#缺点" aria-label="Permalink to &quot;缺点&quot;">​</a></h3><ol><li>如果频率太低，两次快照之间服务器发生宕机，就可能丢失比较多的数据；</li><li>如果频率太高，造成额外的性能开销；</li></ol><h3 id="tips" tabindex="-1">tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;tips&quot;">​</a></h3><ol><li><p>RDB文件加载工作实在服务器启动时自动执行的，Redis并没有提供专门加载RDB文件的命令；</p></li><li><p>可以配置save时机</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">save</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 900</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 900s之内，redis数据修改了1次</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">save</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 300</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 300s之内，redis数据修改了10次</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">save</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 60</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 60s之内，redis数据修改了10000次</span></span></code></pre></div></li></ol><h2 id="aof" tabindex="-1">AOF <a class="header-anchor" href="#aof" aria-label="Permalink to &quot;AOF&quot;">​</a></h2><h3 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h3><ol><li>AOF持久化记录了Redis执行的所有写操作命令，并在Redis重启时，通过重新执行这些命令来重建数据</li><li>AOF默认关闭</li></ol><p>如果需要开启AOF，需要在redis.conf中进行如下的配置；</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">appendonly</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yes</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 表示是否开启AOF持久化</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">appendfilename</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;appendonly.aof&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # AOF持久化文件的名称</span></span></code></pre></div><img src="https://s2.loli.net/2024/04/17/RPiE9WJa5X8d213.png" alt="img" style="zoom:80%;"><h3 id="过程" tabindex="-1">过程 <a class="header-anchor" href="#过程" aria-label="Permalink to &quot;过程&quot;">​</a></h3><ol><li>客户端发送指令；</li><li>redis执行指令，写入内存；</li><li>如果指令执行成功，redis记录命令追加到server.aof_buf缓冲区；</li><li>通过write()系统调用，将缓冲区的内容数据写入到AOF文件中，位于page_cache中；</li><li>通过写回策略，将page_cache中的内容写入到磁盘中；</li></ol><h3 id="写回策略" tabindex="-1">写回策略 <a class="header-anchor" href="#写回策略" aria-label="Permalink to &quot;写回策略&quot;">​</a></h3><ol><li>always：每次执行完指令，直接将AOF文件同步到磁盘中；</li><li>EverySec：写到AOF文件中后，每1s同步缓冲区的内容到磁盘中；</li><li>No：redis不控制从page_cache到磁盘的操作，由操作系统来决定；</li><li>这三种策略都是通过fsync()系统调用进行操作的；</li></ol><h3 id="aof重写机制" tabindex="-1">AOF重写机制 <a class="header-anchor" href="#aof重写机制" aria-label="Permalink to &quot;AOF重写机制&quot;">​</a></h3><p>重写机制的提出，主要是为了解决AOF文件太大的问题；</p><p>当文件大小超过阈值，就会触发重写机制，来压缩AOF文件；</p><p><strong>具体做法</strong>：通过读取key最新的value，然后用一条新的命令记录，写到AOF文件中即可，之前的旧命令直接删除；<strong>一般重写AOF文件，需要新建一个文件，避免因为重写失败，造成的数据污染</strong>；</p><h3 id="优点-1" tabindex="-1">优点 <a class="header-anchor" href="#优点-1" aria-label="Permalink to &quot;优点&quot;">​</a></h3><ol><li>数据安全性高，因为AOF是实时记录写操作，在Redis宕机时，不会出现数据丢失</li></ol><h3 id="缺点-1" tabindex="-1">缺点 <a class="header-anchor" href="#缺点-1" aria-label="Permalink to &quot;缺点&quot;">​</a></h3><ol><li>AOF记录信息很多，文件通常很大</li><li>重建数据时，加载数据比较慢</li></ol><h2 id="混合持久化" tabindex="-1">混合持久化 <a class="header-anchor" href="#混合持久化" aria-label="Permalink to &quot;混合持久化&quot;">​</a></h2><p>提出的原因：解决AOF和RDB各自的优缺点；</p><p>如果想要开启混合持久化功能，可以在 Redis 配置文件将下面这个配置项设置成 yes：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aof-use-rdb-preamble</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yes</span></span></code></pre></div><h4 id="过程-1" tabindex="-1">过程 <a class="header-anchor" href="#过程-1" aria-label="Permalink to &quot;过程&quot;">​</a></h4><ol><li>AOF重写日志的时候，fork出来的重写子进程会先将主进程共享的内存数据以RDB的方式存到AOF文件中；</li><li>这个过程中的操作命令记录在重写缓冲区中；</li><li>重写缓冲区的增量命令以AOF的方式添加到AOF文件中；</li></ol><img src="https://s2.loli.net/2024/04/17/uHoh7jcMFZVtPSY.jpg" alt="图片" style="zoom:80%;">`,42),h=[t];function o(n,r,d,p,c,k){return i(),s("div",null,h)}const g=a(l,[["render",o]]);export{b as __pageData,g as default};
